INSERT INTO features VALUES('S01','EPIC-GOV','GOV-GUARDRAILS','Risk-class guardrail policy',0,3,'planned','P0','guardrail-policy','internal','agentic-tooling','["governance","security"]','["agent","maintainer"]','["governance.read","governance.write"]','["config/agentic/guardrails.json","scripts/guardrail-check.mjs"]','Declarative deny-by-default policy in config/agentic/guardrails.json, validated by a standalone checker. Risk classes map tools to confirmation requirements and required evidence.','','seed');
INSERT INTO features VALUES('S02','EPIC-GOV','GOV-AUDIT','Append-only audit log',0,3,'planned','P0','append-only-audit','internal','agentic-tooling','["governance"]','["agent","maintainer"]','["governance.write"]','["scripts/validate-audit.mjs","scripts/record-audit.mjs","data/audit/audit-log.jsonl"]','Event-sourced JSONL log mirrored into the audit_events table. Never rewritten; corrections are appended as comment/decision events.','','seed');
INSERT INTO features VALUES('S03','EPIC-GOV','GOV-EVALS','Agent evals and AI-security scenarios',1,5,'planned','P1','agent-evals','internal','agentic-tooling','["security","governance"]','["agent","maintainer"]','["governance.read"]','["scripts/run-agent-evals.mjs","tooling/agent-evals/scenarios"]','Scenario fixtures mapped to OWASP LLM and NIST AI-RMF risks, scored against the guardrail policy. Results mirrored into SQLite/SQL/JSON.','','seed');
INSERT INTO features VALUES('S04','EPIC-GOV','GOV-DORA','DORA-style delivery metrics',2,3,'planned','P2','dora-metrics','internal','metrics','["metrics","governance"]','["maintainer"]','["governance.read"]','["scripts/dora-metrics.mjs","data/audit/audit-log.jsonl"]','Local proxies for deployment frequency, change lead time, and change failure rate derived from git history and the audit log.','','seed');
INSERT INTO features VALUES('S05','EPIC-CTX','CTX-BACKLOG','SQL-first backlog engine',0,8,'planned','P0','sql-backlog','internal','agentic-tooling','["context","tooling","governance"]','["agent","maintainer"]','["backlog.read","backlog.write"]','["scripts/backlog-db.mjs","data/schema.sql","data/seed/backlog.seed.json"]','Single local SQLite database rebuilt from a JSON seed and the audit log. Items move through a claim/start/complete/verify lifecycle recorded as immutable events. SQL/.schema dumps are the reviewable mirrors.','','seed');
INSERT INTO features VALUES('S06','EPIC-GOV','GOV-SKILLS','Reusable Codex skills',2,2,'planned','P2','codex-skills','internal','agentic-tooling','["governance","docs"]','["agent"]','["governance.read"]','["skills/agentic-traceability/SKILL.md","skills/agentic-build-runner/SKILL.md","skills/README.md"]','Two skills, traceability and build-runner, installable into ~/.codex/skills. They encode the audit and lifecycle disciplines so they survive across repos and agents.','','seed');
INSERT INTO features VALUES('S07','EPIC-CTX','CTX-BROKER','Context broker and workflow profiles',0,8,'planned','P0','context-broker','internal','agentic-tooling','["context","tooling"]','["agent"]','["backlog.read"]','["scripts/agent-context.mjs","config/agentic/context-profiles.yaml","tooling/agent-context/README.md"]','SQLite chooses the context. A workflow profile picks the queries and caps; the broker emits a bounded packet (feature, items, routes, recent audit, next files) in markdown, json, or toon, and forbids bulk-loading generated mirrors.','CLI packet output intended to be pasted into, or read by, an agent before it opens any source files.','seed');
