INSERT INTO audit_events VALUES('AUD-20260607112309-99cdb8','2026-06-07T11:23:09.147Z','zach','evidence','platform','','','','Created Mac Fan Profile shell script and AppleScript app artifact','Added a local UI wrapper that can set fans to maximum or reset to automatic when a supported smcfan backend is installed; verified build without changing fan speed.','["artifacts/mac-fan-profile/fan-profile.sh","artifacts/mac-fan-profile/Mac Fan Profile.app","artifacts/mac-fan-profile/build-app.sh","bash -n artifacts/mac-fan-profile/fan-profile.sh artifacts/mac-fan-profile/build-app.sh","plutil -lint artifacts/mac-fan-profile/Mac Fan Profile.app/Contents/Info.plist"]','asserted');
INSERT INTO audit_events VALUES('AUD-20260607112750-0f4cc5','2026-06-07T11:27:50.147Z','zach','evidence','platform','','','','Updated Mac Fan Profile to support FanControl CLI backend','Installed FanControl.app v1.5.19 into ~/Applications after notarization verification and rebuilt the wrapper app; status path now reads fan state without changing speed.','["artifacts/mac-fan-profile/fan-profile.sh","artifacts/mac-fan-profile/README.md","~/Applications/FanControl.app/Contents/MacOS/fan --version","artifacts/mac-fan-profile/fan-profile.sh status","codesign --verify --deep --strict --verbose=2 FanControl.app","spctl --assess --type execute --verbose=4 FanControl.app"]','asserted');
INSERT INTO audit_events VALUES('AUD-20260607112845-1b0a5b','2026-06-07T11:28:45.265Z','zach','evidence','platform','','','','Placed FanControl backend in /Applications for helper registration','Moved FanControl.app v1.5.19 from ~/Applications to /Applications so its embedded fan CLI and SMAppService helper use the expected bundle location; verified status read through the wrapper.','["/Applications/FanControl.app/Contents/MacOS/fan","artifacts/mac-fan-profile/fan-profile.sh status"]','asserted');
INSERT INTO audit_events VALUES('AUD-20260607113610-c0ad20','2026-06-07T11:36:10.064Z','zach','evidence','platform','','','','Added live temperature graph and CSV logging to Mac Fan Profile app','Replaced the AppleScript dialog with a native SwiftUI app that samples FanControl/iSMC telemetry, graphs current and chip max temperatures, shows current/max/session values, and appends temperature-log.csv beside the app while running.','["artifacts/mac-fan-profile/MacFanProfileApp.swift","artifacts/mac-fan-profile/Mac Fan Profile.app","artifacts/mac-fan-profile/temperature-log.csv","Mac Fan Profile --sample-once","Mac Fan Profile --log-once","plutil -lint artifacts/mac-fan-profile/Mac Fan Profile.app/Contents/Info.plist","codesign --verify --deep --strict --verbose=2 artifacts/mac-fan-profile/Mac Fan Profile.app"]','asserted');
INSERT INTO audit_events VALUES('AUD-20260607114437-e35ba0','2026-06-07T11:44:37.959Z','zach','evidence','platform','','','','Updated Mac Fan Profile for CPU/GPU overlays, fan-speed logging, and one-time admin fallback','Added GPU temperature sampling and graph overlay, changed CSV schema to include fan_speed_rpm at sample time, archived older log schema automatically, and changed fan writes to try the helper path before a one-time administrator fallback.','["artifacts/mac-fan-profile/MacFanProfileApp.swift","artifacts/mac-fan-profile/fan-profile.sh","artifacts/mac-fan-profile/temperature-log.csv","Mac Fan Profile --sample-once","Mac Fan Profile --log-once","fan list shows Auto target 1000"]','asserted');
INSERT INTO audit_events VALUES('AUD-20260607115543-12a048','2026-06-07T11:55:43.754Z','zach','evidence','platform','','','','Added clickable CPU/GPU detail graphs, usage overlays, and fan RPM graph overlay','Mac Fan Profile now supports CPU and GPU metric clicks for per-core/per-sensor temperature graphs, logs CPU/GPU usage alongside temperatures and fan_speed_rpm, overlays optional usage percent and fan RPM on the graph, and keeps fan control returned to macOS Auto.','["artifacts/mac-fan-profile/MacFanProfileApp.swift","artifacts/mac-fan-profile/README.md","artifacts/mac-fan-profile/temperature-log.csv","Mac Fan Profile --log-once","fan list shows Auto target 1000"]','asserted');
INSERT INTO audit_events VALUES('AUD-20260607121102-4c842e','2026-06-07T12:11:02.471Z','zach','evidence','platform','','','','Changed Mac Fan Profile admin fallback to once per app launch','Fan write actions now try FanControl helper-backed CLI first; if blocked, the app requests administrator approval at most once per running app process and never for passive monitoring, refresh, graphing, or CSV logging.','["artifacts/mac-fan-profile/MacFanProfileApp.swift","artifacts/mac-fan-profile/README.md","Mac Fan Profile --sample-once","Mac Fan Profile --log-once","fan list shows Auto target 1000"]','asserted');
INSERT INTO audit_events VALUES('AUD-20260607122558-4773d7','2026-06-07T12:25:58.798Z','zach','evidence','platform','','','','Fixed Mac Fan Profile repeated fan-control changes after admin fallback','Adjusted authorization state so successful administrator fallback no longer locks out subsequent fan changes in the same app launch; only a failed/cancelled fallback suppresses repeated attempts. Added Auto +50% middle fan mode and documentation.','["artifacts/mac-fan-profile/MacFanProfileApp.swift","artifacts/mac-fan-profile/fan-profile.sh","artifacts/mac-fan-profile/README.md","Mac Fan Profile --sample-once","Mac Fan Profile --log-once","fan list shows Auto mode"]','asserted');
