INSERT INTO audit_events VALUES('AUD-20260609122648-c41ff2','2026-06-09T12:26:48.389Z','zach','test-result','platform','','','verified','F-A evidence tiers + release gate implemented and verified. evidence_tier (asserted<config<test<live) added to backlog_item_events and audit_events; --tier threaded through backlog:verify and audit:record; release_gate_violations view + backlog:validate check enforce that release-class:* features need a live event to sign off. Closes v0.9.1 F2.','Sensitive classes (deploy/infra/performance/runtime-security/data-residency) declared via release-class:* labels; canonical list in config/agentic/guardrails.json evidence block. Tier of this claim is test: proven by automated gate, the strongest honest tier for a tool with no production system.','["npm run ci:governance","npm run test:backlog-evidence-gate"]','test');
INSERT INTO audit_events VALUES('AUD-20260609123612-9363ed','2026-06-09T12:36:12.985Z','zach','comment','platform','','','','F-A hardening after adversarial multi-agent review: backlog:validate now flags non-canonical release-class:* labels, reading the canonical set from guardrails.json at runtime (single source of truth). Release gate kept fail-safe (any release-class:* is gated); releaseItem tier behaviour documented. Evidence-gate test now 5 checks; ci:governance green.','Resolves review finding (high, 0.95): gate matched any release-class:* not only the canonical five. Chosen resolution flags unknown classes rather than narrowing the gate, preserving deny-by-default fail-safe behaviour.','["npm run ci:governance","npm run test:backlog-evidence-gate"]','test');
INSERT INTO audit_events VALUES('AUD-20260609125627-d66d27','2026-06-09T12:56:27.350Z','zach','test-result','platform','','','verified','F-B conformance doctor implemented, reviewed, and hardened. scripts/adg-doctor.mjs runs 5 checks (tracked-sqlite, tracked-ignored, committed-artifact-gate incl. CI configs, embedded-provenance, claude-sync), exits 1 on drift. Wired into adg:install:status (fails on drift), adg:install/update (warn), and ci:governance. ADG self-conformant. Closes v0.9.1 F1/R1.','Multi-agent review: installer wiring clean (doctor exception-safe, isMain guard, status exit-1-on-drift, warn-not-fail on install/update). High-confidence finding addressed: committed-artifact-gate now scans .github/workflows + GitLab/CircleCI/etc., not only package.json. Comment/scope refinements applied for the other findings.','["npm run ci:governance","npm run adg:doctor","npm run test:adg-doctor"]','test');
INSERT INTO audit_events VALUES('AUD-20260609131925-c2ec2d','2026-06-09T13:19:25.929Z','zach','test-result','platform','','','verified','F-E installer --client claude implemented, reviewed, signed off. adg:install/update --client claude lays down the deterministic Claude Code layer (PreToolUse hook, .claude/settings.json hook+permissions, slash commands, doctor, generator) and a CLAUDE.md generated from the host AGENTS.md, tracked+backed-up in adg-install-state.json. --client base is a first-class downgrade. Base install unchanged.','Multi-agent review: both lenses clean (settings.json valid + correct deny>ask precedence, hook blocks destructive/asks production standalone in host, CLAUDE.md generation idempotent, scripts self-contained, base behaviour preserved, dry-run dry). Low finding (no downgrade path) addressed by making --client base first-class with a pruning test.','["npm run ci:governance","npm run test:adg-install-claude","npm run test:adg-install"]','test');
INSERT INTO audit_events VALUES('AUD-20260609133510-c2829b','2026-06-09T13:35:10.940Z','zach','test-result','platform','','','verified','Optional adapters complete: harness-neutral Codex pre-tool adapter (reuses the locked adg-guardrail-hook.mjs, emits uniform decision) and a read-only governance MCP server (classify_work/context_packet read-only, record_audit append-only). Both reviewed and gated. v0.9.2 plan F-A/F-B/F-E + optional adapters all signed off; ci:governance green.','Multi-agent review: MCP server clean (no shell/flag injection, context_packet side-effect-free, record_audit append-only). Adapter: fixed a high-confidence null-input crash and made it fail CLOSED for mutating tools when the hook cannot run (was fail-open). 8 adapter + 4 MCP checks lock both.','["npm run ci:governance","npm run test:adg-codex-hook","npm run test:adg-mcp"]','test');
INSERT INTO audit_events VALUES('AUD-20260609135541-5c4b09','2026-06-09T13:55:41.169Z','zach','test-result','platform','','','implemented','Created updated ADG executive summary PDF covering Claude integration, connectors, deterministic workflow, evidence tiers, and release-gate updates','Generated output/pdf/agentic-development-platform-executive-summary.pdf from targeted local repository evidence; PDF text extraction and render checks passed.','["output/pdf/agentic-development-platform-executive-summary.pdf","pdfplumber text extraction: pages=7, required sections present","pdftoppm render check: rendered_pages=7"]','test');
INSERT INTO audit_events VALUES('AUD-20260609141050-4f3150','2026-06-09T14:10:50.388Z','zach','test-result','platform','','','verified','Fixed abs() absolute-path bug across 15 governance scripts: abs() now honours an absolute path (path.isAbsolute(file) ? file : path.join(root, file)) instead of re-rooting it under the repo, matching the 3 scripts already fixed. Unblocks absolute --seed/--target/--evidence paths.','Found during F-A (the evidence-gate test had worked around it with path.relative); that test now passes an absolute --seed directly as a regression guard. 18 scripts now consistent.','["npm run ci:governance","npm run test:backlog-evidence-gate"]','test');
INSERT INTO audit_events VALUES('AUD-20260610015504-f1fe71','2026-06-10T01:55:04.416Z','zach','test-result','platform','','','implemented','Added Otterblock copyright and ABN footer note to the ADG executive summary PDF','Stamped every page with Copyright (c) 2026 Otterblock Pty Ltd. ABN 91 614 672 794. All rights reserved.; PDF text extraction and visual render checks passed.','["output/pdf/agentic-development-platform-executive-summary.pdf","pdfplumber text extraction: pages=7, copyright and ABN present","pdftoppm render check: first and final pages visually inspected"]','test');
