INSERT INTO audit_events VALUES('AUD-20260615023513-bcb2bc','2026-06-15T02:35:13.980Z','zach','decision','platform','','','implemented','ADG 1.0 Loop 1: toggleable controls as policy-as-code (always-on pins for destructive-deny/audit-append-only/forbidden-bulk-read; governed audited toggle via adg-toggle-control.mjs); hardened the deterministic hook (closed 5 real bypasses: git -c push, separated rm -r -f, find -delete, curl|bash, audit-log tamper; added billing + control-file guard); evals now drive the REAL hook with 3 new scenarios (indirect injection, multi-agent propagation, toggle-abuse); MCP TOON default + outputSchema/structuredContent + secret redaction; prefix-stable context packet; alignment assessment doc (OWASP LLM Top 10, ISO 42001, Three Lines, ISO 31000).','Judge panel: 7 change units, 3 opus judges each, refute-by-default, 21/21 approve, 0 weakensInvariant, all measured wins re-verified by judges. Measured token deltas: agent:evals stdout 1337 to 94 est tokens (-93%) while adding 3 scenarios; MCP context_packet default 5048 to 1386 est tokens (-73% per call). Deny-by-default and append-only audit strengthened, never weakened. Reason: take ADG 0.9.1 toward 1.0 along security, token, and structured-output axes. Risk: low (additive, gate-verified, negative tests added). Rollback: git revert of the loop-1 changes.','["npm run ci:governance (GATE_EXIT=0)","npm run test:adg-toggles (11/11)","npm run test:adg-hook (27/27)","npm run agent:evals (8 scenarios, 3 hook-probed)","docs/governance-alignment.md","scripts/adg-toggle-control.mjs"]','test');
INSERT INTO audit_events VALUES('AUD-20260615032749-1572d1','2026-06-15T03:27:49.385Z','zach','decision','platform','','','implemented','ADG 1.0 Loop 2 (consolidation + audit integrity): installer now ships the single policy source + validator + governed toggle + audit recorder/chain to hosts with merge-aware update (preserves host governed toggles, never carries a relaxed always-on forward, --force-policy re-baselines); --client codex/both added and the Codex adapter host-hook path + a symlink isMain bug fixed; append-only audit log now carries a rolling hash chain (shared canonicalizer, forward-only, single appendFileSync) where edit/delete/reorder/insert in the chained region is a hard FAIL; doctor controls-drift check (relaxed always-on or unaudited disable = FAIL); read-only control_state MCP tool; broadened destructive coverage (chmod -R 000) + Bash-branch policy-write guard; --quiet gate validators.','Design-reviewed before build (RFC 9162 / research.swtch tlog / GoLogX for the chain). Judge panel: 7 units, 3 opus judges each, refute-by-default, 20/21 approve (the 1 reject was a token-delta lens on a non-token security unit; majority shipped it), 0 weakensInvariant. This event is the chain anchor (prevHash = GENESIS). Measured: guardrail-check 107->15 quiet tokens, validate-audit 67->14. Reason: complete the 1.0 consolidation and audit-integrity axes. Risk: low (additive, gate-verified, negative tests). Rollback: git revert of the loop-2 changes. Deferred (tracked): external git tip-anchor to close hash-chain tail-truncation.','["npm run ci:governance (GATE_EXIT=0)","npm run test:adg-audit-chain (8/8)","npm run test:adg-install-codex (15/15)","npm run test:adg-hook (32/32)","scripts/audit-chain.mjs","docs/audit-chain.md"]','test');
INSERT INTO audit_events VALUES('AUD-20260615034238-a67cc1','2026-06-15T03:42:38.530Z','zach','comment','platform','','','','Hardened audit hash-chain: chain-state high-water-mark sidecar closes the strip-all-hashes laundering (A) and chained-tip truncation (B) holes; legacy prefix frozen by digest (C/D); negative tests added','','["tooling/adg-as-code/test-adg-audit-chain.mjs","scripts/audit-chain.mjs","scripts/validate-audit.mjs"]','test');
INSERT INTO audit_events VALUES('AUD-20260615040439-cea067','2026-06-15T04:04:39.786Z','zach','decision','platform','','','released','ADG 1.0.0 release. Three self-converging ultra-loops took ADG 0.9.1 to 1.0: (L1) toggleable controls as policy-as-code with always-on pins + governed audited toggle, hardened deterministic hook closing 5 real bypasses, evals driving the real hook + injection/propagation/toggle-abuse scenarios, MCP TOON default + structured outputs, prefix-stable context packet, and the governance alignment assessment (OWASP LLM Top 10 / ISO 42001 / Three Lines / ISO 31000); (L2) append-only audit rolling hash chain + high-water-mark sidecar, one-install consolidation shipping a single policy source to the Claude and Codex adapters with merge-aware update, doctor controls-drift, read-only control_state MCP tool, broadened destructive coverage, --quiet validators; (L3) version 1.0.0 across the full surface, AGENTS.md + regenerated CLAUDE.md, README, release notes, the governance-controls release class (live-evidence-required), and a read-only dashboard controls view.','Each loop: research swarm + adversarial gap/design-review swarm + build + odd-judge panel (refute-by-default, distinct lenses) + green ci:governance + consolidated audit event + completeness critic. Judge totals across loops: 21/21 (L1), 20/21 (L2), 14/15 (L3) approve, 0 weakensInvariant in any loop. Deny-by-default and the append-only audit log were strengthened, never weakened; toggling a control is a governed, audited action; always-on controls (destructive deny, audit append-only, forbidden-bulk read) are pinned in code. Measured token deltas: MCP context packet 5048->1386 (-73%/call); agent:evals stdout 1337->94 (-93%); guardrail-check --quiet 107->15; validate-audit --quiet 67->14. No em dashes in generated output. Reason: ADG 1.0 GA. Risk: low (additive, gate-verified, negative tests throughout, 3 independent judge panels). Rollback: git revert to 0.9.1. Deferred post-1.0 (documented in release notes): audit-chain external git tip-anchor, context cachePrefix + broker pagination.','["npm run ci:governance (GATE_EXIT=0)","docs/release-notes-1.0.md","docs/governance-alignment.md","docs/agent-guides/adg-1.0-loop-log.md","package.json version 1.0.0"]','test');
INSERT INTO audit_events VALUES('AUD-20260615073731-5f9de2','2026-06-15T07:37:31.963Z','zach','status','platform','','','implemented','Skills/plugins updated for 1.1 tooling + added context-bound swarm skills. (1) Five existing skills now reference the new deliverable-quality tooling so agents reach for it proactively: adg-quick-ui-fix (run asset:lint on image assets), adg-signoff-reviewer + agentic-traceability + adg-evidence-curator (release-class:visual + live rendered-artifact evidence + completeness-critic), adg-feature-elicitation (check uncovered-intent gaps). (2) Three new orchestration skills encode a context-bound, backlog-logged swarm to cut tokens: adg-backlog-decompose (Opus/Sonnet planner logs small items), adg-item-worker (Sonnet/Haiku works one item under its bounded packet), adg-backlog-swarm (parent orchestrates, keeps integration + audit log).','Skills are playbooks over existing ADG primitives (backlog lifecycle, agent:loop worklist, context:item, write-scope); no new runtime. Measured token basis for the swarm: one item packet is 1353 est tokens (TOON) vs 5048 for the whole-feature monolith, and workers do not accumulate sibling context. skills:validate green (19 skills), all under maxSkillBytes 5000, no forbidden terms. Reason: friend-agent feedback (agents should use the new gates) + cut token usage further. Risk: low (skills are advisory prompts; deterministic gates unchanged). Rollback: git revert the skill changes + remove the 3 manifest entries.','["npm run ci:governance (GATE_EXIT=0)","npm run skills:validate (19 skills)","skills/adg-backlog-swarm/SKILL.md","config/agentic/skill-manifest.json"]','test');
INSERT INTO audit_events VALUES('AUD-20260615111655-9bb254','2026-06-15T11:16:55.937Z','zach','verify','platform','','','implemented','Closed 9 verified ADG_WRITE_SCOPE write-scope bypasses in the deterministic PreToolUse hook (adg-guardrail-hook.mjs): (1) normRel now collapses ../ before scope match; (2) patch positional/-o blocked; (3) git apply/am/pull/merge/rebase/cherry-pick/restore/checkout/stash blocked incl. global-option insertion; (4) tee extracts all file args; (5) cp <stdin redirect no longer hides dest; (6) >| noclobber-override detected; (7) python/node/perl/ruby/swift inline one-liners refused under scope; (8) ed/ex line editors refused; (9) ln symlink points-at target scope-checked. Single hook enforces both Claude + Codex clients.','','["test-adg-guardrail-hook 60/60; test-adg-write-scope 57/57 (Claude hook + Codex adapter); agent:evals 8/8; npm run ci:governance exit 0; direct adversarial probes confirm exit 2 for all 9 escapes and exit 0 for in-scope writes/reads"]','test');
INSERT INTO audit_events VALUES('AUD-20260615111738-1299d6','2026-06-15T11:17:38.887Z','zach','test-result','platform','','','implemented','Corrective re-classification of AUD-20260615111655-9bb254 (recorded with non-canonical eventType ''verify''): canonical type is ''test-result''. Same fact stands — the 9 ADG_WRITE_SCOPE bypasses in adg-guardrail-hook.mjs are closed and verified by passing tests.','','["test-adg-guardrail-hook 60/60; test-adg-write-scope 57/57 (Claude hook + Codex adapter); agent:evals 8/8; ci:governance exit 0; adversarial probes exit 2 on all 9 escapes, exit 0 in-scope"]','test');
INSERT INTO audit_events VALUES('AUD-20260615131619-51e8f1','2026-06-15T13:16:19.155Z','zach','test-result','platform','','','implemented','ADG_WRITE_SCOPE hardening converged after 13 adversarial judge rounds (rounds 5-13 beyond the first 9 bypasses). Closed write channels: download/move/compress output flags (curl -o/-O, wget -O and bare, gzip family, sort and shuf -o, uniq output positional); embedded shell-expansion targets now fail closed; compile/link/crypto/doc output flags (cc/gcc/clang/go/ld/objcopy/rollup/babel/pandoc/rustc -o, openssl -out, --out long flags); in-place rewriters (prettier/eslint/stylelint/gofmt/clang-format/autopep8/yapf/biome/black/isort/rustfmt/ruff) with per-tool read-only-mode and per-group value-flag handling; sed -i multi-file; perl and ruby -ne loops; deno eval; bash -c and sh -c; pipe into a bare shell; NotebookEdit notebook_path. Fixed over-blocks: grep with a build-tool search term plus -o, git stash list/show and merge/rebase --abort, separated value-flag values mis-read as paths. Documented residual: program-that-writes (node build.js, make), niche in-place data processors (yq, jq), obfuscated interpreter code. Final judges returned NO ESCAPE FOUND and NO OVER-BLOCK FOUND.','','["test-adg-write-scope 220/220 (Claude hook + Codex adapter); test-adg-guardrail-hook 61/61; test-adg-codex-hook 8/8; ci:governance exit 0; round-13 escape judge NO ESCAPE FOUND; round-12 over-block judge clean across 53 verified commands"]','test');
INSERT INTO audit_events VALUES('AUD-20260620051927-3d1f29','2026-06-20T05:19:27.704Z','zach','status','feature','S01','S01','in-progress','Add P9 subagent budget gate: packages/core/subagent-gate.mjs (pure decision) + PreToolUse/Task & SubagentStop hook bounding fan-out (maxConcurrent/maxTotal) per loop-budget.json; quality gate, fails open, default warn. 13 unit/negative checks + live hook smoke; wired into ci:governance (green). Adds docs/adg-scorecard.md and research/agentic-field-map-2026-06-20.md.','','[]','test');
INSERT INTO audit_events VALUES('AUD-20260620053449-f88592','2026-06-20T05:34:49.063Z','zach','status','feature','S07','S07','in-progress','Research-to-release loop (governed, bounded, L0-classified, treated as L2 writes): produced research/gap-analysis.md (P1-P12 + 6 §9 open questions, each with a plan), research/improvement-plan.md (I1-I8 anchored testable improvements + no-action rationale), research/component-disposition.md (every component KEEP/UPDATE/REPLACE, no RETIRE), and a full README.md rewrite (9 sections: what/use-cases/loops/12-areas/setup/harnesses/Claude/Codex/coming-soon/context-benefits). All commands verified against package.json; abstract model tiers only. Verifiers green: ci:governance EXIT=0, adg:doctor 6/6.','','[]','test');
INSERT INTO audit_events VALUES('AUD-20260620055904-2a4cae','2026-06-20T05:59:04.450Z','zach','comment','feature','S07','S07','','Research-to-release loop re-verification on the COMMITTED tree (commit e51637f). Independently re-checked the four loop artifacts against their step verifiers: gap-analysis.md (P1-P12 + 6 §9 questions + P9 cross-parity, each with a plan), improvement-plan.md (I1-I9 anchored testable improvements + no-action rationale), component-disposition.md (every enumerated component dispositioned; no RETIRE), and the README rewrite (all 9 sections). All complete; no regeneration needed (look-before-replace, P10). Ground-truth gates re-run on clean tree: ci:governance EXIT=0, adg:doctor 6/6, zero tracked drift. Prior loop event AUD-20260620053449-f88592 was recorded in-progress on an uncommitted tree; this closes it out post-commit.','','[]','test');
INSERT INTO audit_events VALUES('AUD-20260620061239-86ab34','2026-06-20T06:12:39.357Z','zach','status','feature','S07','S07','in-progress','Add docs/agent-setup-guide.md: a paste-into-an-agent runbook to set up ADG (evaluate the repo / install into a host via adg:init|adg:install / configure config/agentic / operate under the lanes+audit+release-gate rules). Grounded in a research+verify workflow over scripts/adg-init.mjs, adg-install.mjs, adg-doctor.mjs, package.json, AGENTS.md, adg-mcp-server.mjs; then adversarially reviewed (command accuracy / completeness / doctor-safety) — all lenses clean. Corrections baked in: MCP server exposes FOUR tools (incl. control_state), ci:governance does not end at adg:doctor, --client accepts base, model IDs isolated to models.json. README links the guide. ci:governance EXIT=0, adg:doctor 6/6. Committing + pushing per user request.','','[]','test');
INSERT INTO audit_events VALUES('AUD-20260620062417-88c898','2026-06-20T06:24:17.647Z','zach','comment','platform','','','','AGENTS.md: correct governance MCP server tool list to include read-only control_state (4 tools: classify_work, context_packet, control_state, record_audit); regenerated CLAUDE.md; adg:doctor claude-sync clean','','[]','test');
INSERT INTO audit_events VALUES('AUD-20260620063218-9d7fc6','2026-06-20T06:32:18.364Z','zach','status','feature','S01','S01','implemented','ADG v2.0.0 official release: root package.json 1.1.0 -> 2.0.0 (matches @adg/core, @adg/sdk, @adg/cli at 2.0.0); docs/release-notes-2.0.md added (tiered governed harness + SDK over vendor loops: governor, backpressure, context-lifecycle hooks, subagent fan-out cap, model orchestrator, @adg/sdk Claude+OpenAI adapters, Codex lifecycle adapters, adg init + surface parity, agent setup guide; deferred follow-ups labeled, not shipped); README v2.0 callout + release-notes link. Release notes adversarially verified (no-overclaim / accuracy / style+doctor-safety) all clean. Full gate green: ci:governance EXIT=0, adg:doctor 6/6. Merging to main and tagging v2.0.0.','','[]','test');
